import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"本草纲目","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/08-本草纲目（李时珍）.md","filePath":"tcm-data/04-明清/08-本草纲目（李时珍）.md","lastUpdated":1781084559000}'),n={name:"tcm-data/04-明清/08-本草纲目（李时珍）.md"};function o(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="本草纲目" tabindex="-1">本草纲目 <a class="header-anchor" href="#本草纲目" aria-label="Permalink to &quot;本草纲目&quot;">​</a></h1><blockquote><p>李时珍（1518-1593年），湖北蕲州人 中国古代最伟大的博物学家、药学家 代表作：《本草纲目》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字东璧，号濒湖</li><li><strong>生平</strong>：三次科举不第，后弃儒从医。发现前代本草错误甚多，立志重修</li><li><strong>编纂历程</strong>：<strong>27年</strong>（1552-1578年），走遍大江南北，访采四方</li><li><strong>卷数</strong>：52卷，约190万字</li><li><strong>规模</strong>：载药<strong>1892种</strong>（新增374种），附方<strong>11096首</strong>，附图<strong>1109幅</strong></li><li><strong>学术地位</strong>：<strong>中国古代最大的博物学著作</strong>，&quot;东方药物巨典&quot;</li></ul><h3 id="达尔文的评价" tabindex="-1">达尔文的评价 <a class="header-anchor" href="#达尔文的评价" aria-label="Permalink to &quot;达尔文的评价&quot;">​</a></h3><p>达尔文在《物种起源》中引用《本草纲目》，称之为&quot;中国古代的百科全书&quot;。</p><hr><h2 id="二、核心贡献" tabindex="-1">二、核心贡献 <a class="header-anchor" href="#二、核心贡献" aria-label="Permalink to &quot;二、核心贡献&quot;">​</a></h2><h3 id="_1-药物分类法-——-世界领先" tabindex="-1">1. 药物分类法 —— 世界领先 <a class="header-anchor" href="#_1-药物分类法-——-世界领先" aria-label="Permalink to &quot;1. 药物分类法 —— 世界领先&quot;">​</a></h3><p>李时珍采用了**&quot;从微至巨&quot;**的分类方法，比林奈的生物分类法早约200年：</p><table tabindex="0"><thead><tr><th style="text-align:left;">部</th><th style="text-align:left;">内容</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>水部</strong></td><td style="text-align:left;">各种水（天水、地水）</td><td style="text-align:left;">从最简单开始</td></tr><tr><td style="text-align:left;"><strong>火部</strong></td><td style="text-align:left;">各种火</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>土部</strong></td><td style="text-align:left;">各种土</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>金石部</strong></td><td style="text-align:left;">矿物、金属</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>草部</strong></td><td style="text-align:left;">草本植物</td><td style="text-align:left;">山草、芳草、湿草、毒草等</td></tr><tr><td style="text-align:left;"><strong>谷部</strong></td><td style="text-align:left;">谷物</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>菜部</strong></td><td style="text-align:left;">蔬菜</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>果部</strong></td><td style="text-align:left;">水果</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>木部</strong></td><td style="text-align:left;">木本植物</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>服器部</strong></td><td style="text-align:left;">日常用品</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>虫部</strong></td><td style="text-align:left;">昆虫</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>鳞部</strong></td><td style="text-align:left;">鱼类、爬行类</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>介部</strong></td><td style="text-align:left;">龟、鳖、蚌类</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>禽部</strong></td><td style="text-align:left;">鸟类</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>兽部</strong></td><td style="text-align:left;">哺乳动物</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>人部</strong></td><td style="text-align:left;">人的排泄物等</td><td style="text-align:left;"></td></tr></tbody></table><h3 id="_2-每药体例-——-标准化描述" tabindex="-1">2. 每药体例 —— 标准化描述 <a class="header-anchor" href="#_2-每药体例-——-标准化描述" aria-label="Permalink to &quot;2. 每药体例 —— 标准化描述&quot;">​</a></h3><p>每味药物按以下结构详述：</p><ol><li><strong>释名</strong> → 解释名称由来</li><li><strong>集解</strong> → 产地、形态</li><li><strong>修治</strong> → 炮制方法</li><li><strong>气味</strong> → 四气五味</li><li><strong>主治</strong> → 主要功效</li><li><strong>发明</strong> → 李时珍的独家见解（最重要部分）</li><li><strong>附方</strong> → 相关方剂</li></ol><h3 id="_3-纠错-——-纠正前代之误" tabindex="-1">3. 纠错 —— 纠正前代之误 <a class="header-anchor" href="#_3-纠错-——-纠正前代之误" aria-label="Permalink to &quot;3. 纠错 —— 纠正前代之误&quot;">​</a></h3><p>李时珍纠正了大量前代本草的错误，例如：</p><ul><li><strong>南星与虎掌</strong>：前人混为一物，李氏辨明为同一种植物的不同部位</li><li><strong>五倍子</strong>：前人认为是植物果实，李氏发现是虫瘿</li></ul><hr><h2 id="三、李时珍的用药思想" tabindex="-1">三、李时珍的用药思想 <a class="header-anchor" href="#三、李时珍的用药思想" aria-label="Permalink to &quot;三、李时珍的用药思想&quot;">​</a></h2><h3 id="_1-重视民间经验" tabindex="-1">1. 重视民间经验 <a class="header-anchor" href="#_1-重视民间经验" aria-label="Permalink to &quot;1. 重视民间经验&quot;">​</a></h3><blockquote><p><strong>「虽曰医者意也，而用药之理，不可不穷。」</strong></p></blockquote><p>李时珍大量收集民间偏方验方。</p><h3 id="_2-重视药性配伍" tabindex="-1">2. 重视药性配伍 <a class="header-anchor" href="#_2-重视药性配伍" aria-label="Permalink to &quot;2. 重视药性配伍&quot;">​</a></h3><blockquote><p><strong>「药有七情：独行、相须、相使、相畏、相恶、相反、相杀。」</strong></p></blockquote><p>他对药物配伍的论述比《神农本草经》更为精细。</p><h3 id="_3-重视产地与炮制" tabindex="-1">3. 重视产地与炮制 <a class="header-anchor" href="#_3-重视产地与炮制" aria-label="Permalink to &quot;3. 重视产地与炮制&quot;">​</a></h3><blockquote><p><strong>「凡诸草木昆虫，产之有地；根叶花实，采之有时。」</strong></p></blockquote><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「天下无难事，只怕有心人。」</strong></p></blockquote><blockquote><p><strong>「虽曰医者意也，而用药之理，不可不穷。」</strong></p></blockquote><blockquote><p><strong>「凡诸草木昆虫，产之有地；根叶花实，采之有时。」</strong></p></blockquote><blockquote><p><strong>「人之所病，病疾多；医之所病，病道少。」</strong></p></blockquote><blockquote><p><strong>「千里马常有，而伯乐不常有。」</strong>（喻好药常有而善用药者少）</p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="中医领域" tabindex="-1">中医领域 <a class="header-anchor" href="#中医领域" aria-label="Permalink to &quot;中医领域&quot;">​</a></h3><ul><li>清代《本草备要》《本草从新》等皆以《纲目》为蓝本</li><li>现代《中华本草》的体例也受其影响</li></ul><h3 id="科学领域" tabindex="-1">科学领域 <a class="header-anchor" href="#科学领域" aria-label="Permalink to &quot;科学领域&quot;">​</a></h3><ul><li>被翻译成英、法、德、日、俄等多国文字</li><li>达尔文、李约瑟等西方科学家高度评价</li></ul><h3 id="局限" tabindex="-1">局限 <a class="header-anchor" href="#局限" aria-label="Permalink to &quot;局限&quot;">​</a></h3><ul><li>受时代限制，也收录了一些迷信内容（如&quot;人部&quot;中的粪清、尿垢等）</li><li>对某些药物的功效描述夸大</li><li>需要批判性地继承</li></ul><hr><h2 id="六、李时珍与黄元御的对比" tabindex="-1">六、李时珍与黄元御的对比 <a class="header-anchor" href="#六、李时珍与黄元御的对比" aria-label="Permalink to &quot;六、李时珍与黄元御的对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">李时珍</th><th style="text-align:left;">黄元御</th></tr></thead><tbody><tr><td style="text-align:left;">立场</td><td style="text-align:left;">广收博采，兼收并蓄</td><td style="text-align:left;">尊经复古，排斥后世</td></tr><tr><td style="text-align:left;">用药</td><td style="text-align:left;">大量时方、验方</td><td style="text-align:left;">精选经方</td></tr><tr><td style="text-align:left;">本草观</td><td style="text-align:left;">1892种，穷尽天下药物</td><td style="text-align:left;">仅取常用药百种左右</td></tr><tr><td style="text-align:left;">影响</td><td style="text-align:left;">世界性博物学巨著</td><td style="text-align:left;">中医理论体系完善者</td></tr><tr><td style="text-align:left;">共同点</td><td style="text-align:left;">都极其勤奋，都是划时代的人物</td><td style="text-align:left;"></td></tr></tbody></table><hr><p><em>本条目为精简框架版。可在后续扩展至《本草纲目》常用药精选（200味核心药）、附方精选、与《神农本草经》的药物认识演变对比等专题。</em></p>',48)])])}const u=e(n,[["render",o]]);export{x as __pageData,u as default};
